import { generateText, tool } from "ai";
import { anthropic } from "@ai-sdk/anthropic";
import { z } from "zod";

type ToolCallResult = {
  toolCallId: string;
  toolName: string;
  args: unknown;
  errored: true;
  errorMessage: string;
} | {
  toolCallId: string;
  toolName: string;
  args: unknown;
  errored: false;
  result: unknown;
};

async function callWithErroringTool(): Promise<ToolCallResult> {
  const result = await generateText({
    model: anthropic("claude-haiku-4-5-20251001"),
    tools: {
      alwaysErrors: tool({
        description: "A tool that always throws an error.",
        parameters: z.object({
          input: z.string().describe("Any input string"),
        }),
        execute: async () => {
          throw new Error("This tool always fails intentionally.");
        },
      }),
    },
    toolChoice: { type: "tool", toolName: "alwaysErrors" },
    prompt: "Use the alwaysErrors tool with any input.",
  });

  for (const step of result.steps) {
    for (const part of step.toolResults) {
      if (part.type === "tool-result") {
        return {
          toolCallId: part.toolCallId,
          toolName: part.toolName,
          args: part.args,
          errored: false,
          result: part.output,
        };
      }
      if (part.type === "tool-error") {
        return {
          toolCallId: part.toolCallId,
          toolName: part.toolName,
          args: part.args,
          errored: true,
          errorMessage: String(part.error),
        };
      }
    }
  }

  throw new Error("No tool result found in response.");
}

callWithErroringTool().then((res) => {
  console.log(JSON.stringify(res, null, 2));
});

